function formatTxHash(hash: string) {
  return hash.slice(0, 6) + "..." + hash.slice(-4);
}

function abbreviateMiddle(value: unknown, start = 8, end = 6) {
  const text = String(value || "");
  if (!text) return "-";
  if (text.length <= start + end + 3) return text;
  return `${text.slice(0, start)}...${text.slice(-end)}`;
}

function formatSwapTokenAmount(token: SwapFeeToken) {
  const n = Number(formatUnits(token.amount, token.decimals));
  if (!Number.isFinite(n)) return `0 ${token.symbol}`;
  return `${n.toLocaleString(undefined, { maximumFractionDigits: 6 })} ${token.symbol}`;
}

function getTokenUsdValue(token: SwapFeeToken) {
  const priceUsd = token.priceUsd ?? getStablecoinUsdFallback(token.symbol);
  if (!priceUsd) return null;
  const amount = Number(formatUnits(token.amount, token.decimals));
  if (!Number.isFinite(amount)) return null;
  return amount * priceUsd;
}

function getStablecoinUsdFallback(symbol: string) {
  return [
    "USDC",
    "USDT",
    "DAI",
    "USDE",
    "USDS",
    "USD0",
    "PYUSD",
    "FDUSD",
  ].includes(symbol.toUpperCase())
    ? 1
    : null;
}

async function fetchWithRetry(url: string, options: RequestInit = {}) {
  let lastError: Error | null = null;
  for (let attempt = 0; attempt < 3; attempt += 1) {
    try {
      const response = await fetch(url, options);
      if (response.status === 429 && attempt < 2) {
        await new Promise(resolve =>
          window.setTimeout(resolve, 1000 * 2 ** attempt)
        );
        continue;
      }
      return response;
    } catch (error) {
      lastError = error instanceof Error ? error : new Error(String(error));
      if (attempt < 2)
        await new Promise(resolve =>
          window.setTimeout(resolve, 1000 * 2 ** attempt)
        );
    }
  }
  throw lastError || new Error("Failed to fetch token metadata.");
}

async function getEthPrice() {
  const cacheKey = "coingecko_eth_price";
  const cached = readCachedTokenData<{ price: number }>(cacheKey);
  if (cached) return cached.price;
  const response = await fetchWithRetry(
    "https://api.coingecko.com/api/v3/simple/price?ids=ethereum&vs_currencies=usd"
  );
  if (!response.ok) return null;
  const data = await response.json();
  const price = data.ethereum?.usd || null;
  if (price) writeCachedTokenData(cacheKey, { price });
  return price;
}

async function getTokenInfo(chainId: string, address: string) {
  const cacheKey = `coingecko_token_${chainId}_${address.toLowerCase()}`;
  const cached = readCachedTokenData<{
    price: number | null;
    logo: string | null;
  }>(cacheKey);
  if (cached) return cached;
  const platformId =
    chainId === "ethereum"
      ? "ethereum"
      : chainId === "arbitrum"
        ? "arbitrum-one"
        : "base";
  const response = await fetchWithRetry(
    `https://api.coingecko.com/api/v3/coins/${platformId}/contract/${address.toLowerCase()}`
  );
  if (!response.ok) return null;
  const data = await response.json();
  const result = {
    price: data.market_data?.current_price?.usd || null,
    logo: data.image?.small || data.image?.thumb || null,
  };
  writeCachedTokenData(cacheKey, result);
  return result;
}

function readCachedTokenData<T>(key: string): T | null {
  if (typeof window === "undefined") return null;
  try {
    const raw = localStorage.getItem(key);
    if (!raw) return null;
    const parsed = JSON.parse(raw) as T & { timestamp?: number };
    if (!parsed.timestamp || Date.now() - parsed.timestamp > 60 * 60 * 1000) {
      localStorage.removeItem(key);
      return null;
    }
    return parsed;
  } catch {
    return null;
  }
}

function writeCachedTokenData(key: string, data: unknown) {
  if (typeof window === "undefined") return;
  try {
    localStorage.setItem(
      key,
      JSON.stringify({ ...(data as object), timestamp: Date.now() })
    );
  } catch {
    // Ignore cache write failures.
  }
}

async function withSwapFeeProvider<T>(
  chain: SwapFeeChain,
  run: (provider: Provider) => Promise<T>
): Promise<T> {
  let lastError: unknown;
  for (const rpcUrl of [chain.rpcUrl, ...(chain.fallbackRpcUrls || [])]) {
    try {
      return await run(
        new JsonRpcProvider(rpcUrl, chain.chainId, { staticNetwork: true })
      );
    } catch (error) {
      lastError = error;
    }
  }
  throw lastError instanceof Error
    ? lastError
    : new Error("Failed to read swap fees from supported RPCs.");
}

async function loadSwapFeesForChain(
  chain: SwapFeeChain,
  brokerAddress: string
): Promise<SwapFeeChain> {
  return withSwapFeeProvider(chain, async provider => {
    const contract = new ethers.Contract(
      WOOFI_WIDGET_ROUTER_ADDRESS,
      WOOFI_WIDGET_ROUTER_ABI,
      provider
    );
    const tokenCount =
      await contract.getBrokerClaimableTokensLength(brokerAddress);
    if (tokenCount === 0n)
      return {
        ...chain,
        tokens: [],
        totalUsd: 0,
        isLoading: false,
        error: null,
      };

    const tokenAddresses: string[] = await contract.getBrokerClaimableTokens(
      brokerAddress,
      0,
      tokenCount
    );
    const tokenResults = await Promise.all(
      tokenAddresses.map(async (tokenAddress): Promise<SwapFeeToken | null> => {
        const amount: bigint = await contract.brokerFees(
          brokerAddress,
          tokenAddress
        );
        if (amount === 0n) return null;
        const isNative =
          tokenAddress.toLowerCase() === ETH_PLACEHOLDER_ADDRESS.toLowerCase();
        if (isNative) {
          const ethPrice = await getEthPrice().catch(() => null);
          return {
            address: tokenAddress,
            symbol: "ETH",
            decimals: 18,
            amount,
            priceUsd: ethPrice,
            logoUri:
              "https://assets.coingecko.com/coins/images/279/small/ethereum.png",
            isNative: true,
          } satisfies SwapFeeToken;
        }

        const tokenContract = new ethers.Contract(
          tokenAddress,
          ERC20_METADATA_ABI,
          provider
        );
        const [symbol, decimals, tokenInfo] = await Promise.all([
          tokenContract.symbol().catch(() => "UNKNOWN"),
          tokenContract.decimals().catch(() => 18),
          getTokenInfo(chain.id, tokenAddress).catch(() => null),
        ]);
        return {
          address: tokenAddress,
          symbol,
          decimals: Number(decimals),
          amount,
          priceUsd: tokenInfo?.price ?? null,
          logoUri: tokenInfo?.logo ?? null,
          isNative: false,
        } satisfies SwapFeeToken;
      })
    );

    const tokens = tokenResults.filter(
      (token): token is SwapFeeToken => token !== null
    );
    const totalUsd = tokens.reduce(
      (sum, token) => sum + (getTokenUsdValue(token) || 0),
      0
    );
    return { ...chain, tokens, totalUsd, isLoading: false, error: null };
  });
}

