function getDailyFeeRevenue(row: DailyFeeRevenueRow) {
  const total = firstNumber(row, [
    "total_revenue",
    "fee_revenue",
    "daily_fee_revenue",
    "total_fee_revenue",
    "total_broker_fee",
    "totalBrokerFee",
    "broker_fee",
    "brokerFee",
    "builder_fee",
    "builderFee",
    "revenue",
  ]);
  if (total !== null) return total;

  const perp = firstNumber(row, [
    "perp_fee_revenue",
    "perpFeeRevenue",
    "perp_broker_fee",
    "perpBrokerFee",
    "perp_fee",
    "perpFee",
  ]);
  const swap = firstNumber(row, [
    "swap_fee_revenue",
    "swapFeeRevenue",
    "swap_broker_fee",
    "swapBrokerFee",
    "swap_fee",
    "swapFee",
  ]);
  if (perp !== null || swap !== null) return (perp || 0) + (swap || 0);
  return 0;
}

function getRevenueBreakdown(row: DailyFeeRevenueRow): RevenueBreakdownItem[] {
  const items: RevenueBreakdownItem[] = [];

  for (const field of REVENUE_BREAKDOWN_FIELDS) {
    const foundKey = field.keys.find(
      key => row[key] !== null && row[key] !== undefined && row[key] !== ""
    );
    if (!foundKey) continue;
    const value = numberValue(row[foundKey]);
    if (value !== null)
      items.push({ key: foundKey, label: field.label, value });
  }

  const platformTradingFee = firstNumber(row, PLATFORM_TRADING_FEE_KEYS);
  const baseFee = firstNumber(row, BASE_FEE_KEYS);
  const directBuilderFeeRevenue = firstNumber(row, BUILDER_FEE_REVENUE_KEYS);
  const builderFeeRevenue =
    platformTradingFee !== null && baseFee !== null
      ? platformTradingFee - baseFee
      : directBuilderFeeRevenue;
  if (builderFeeRevenue !== null)
    items.push({
      key: "builder_fee_revenue",
      label: "Builder fee revenue",
      value: builderFeeRevenue,
    });

  return items;
}

function formatFeeRevenue(value: number) {
  if (!Number.isFinite(value) || value === 0) return "$0.00";
  const sign = value < 0 ? "-" : "";
  const abs = Math.abs(value);
  if (abs < 0.01) return `${sign}< $0.01`;
  const floored = Math.floor(abs * 100) / 100;
  return `${sign}$${floored.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

function formatFeeRevenueBreakdown(value: number) {
  if (!Number.isFinite(value) || value === 0) return "$0.00";
  const sign = value < 0 ? "-" : "";
  const abs = Math.abs(value);
  if (abs < 0.000001) return `${sign}< $0.000001`;
  const floored = Math.floor(abs * 1_000_000) / 1_000_000;
  return `${sign}$${floored.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 6 })}`;
}

function unwrapDailyFeeRevenueRows(
  payload: DailyFeeRevenueResponse
): DailyFeeRevenueRow[] {
  if (Array.isArray(payload)) return payload;
  if (Array.isArray(payload.rows)) return payload.rows;
  if (Array.isArray(payload.data)) return payload.data;
  if (
    payload.data &&
    !Array.isArray(payload.data) &&
    Array.isArray(payload.data.rows)
  )
    return payload.data.rows;
  return [];
}

function formatDateParam(date: Date) {
  return date.toISOString().slice(0, 10);
}

function getDailyFeeRevenueDateRange() {
  const now = new Date();
  const endDate = new Date(
    Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate())
  );
  const startDate = new Date(endDate);
  startDate.setUTCDate(
    startDate.getUTCDate() - DAILY_FEE_REVENUE_LOOKBACK_DAYS
  );
  return {
    start_date: formatDateParam(startDate),
    end_date: formatDateParam(endDate),
  };
}

function parseDateParam(value: string) {
  const match = value.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (!match) return null;
  const date = new Date(
    Date.UTC(Number(match[1]), Number(match[2]) - 1, Number(match[3]))
  );
  return Number.isNaN(date.getTime()) ? null : date;
}

function validateDailyFeeRevenueDateRange(range: DailyFeeRevenueDateRange) {
  const startDate = parseDateParam(range.start_date);
  const endDate = parseDateParam(range.end_date);
  if (!startDate || !endDate) return "Select a valid start and end date.";
  if (startDate.getTime() > endDate.getTime())
    return "Start date must be before or equal to end date.";
  const diffDays = Math.floor(
    (endDate.getTime() - startDate.getTime()) / ONE_DAY_MS
  );
  if (diffDays > DAILY_FEE_REVENUE_LOOKBACK_DAYS)
    return "Date range must be 180 days or less.";
  return "";
}

