function DateRangeSelector({
  value,
  onChange,
  onApply,
  loading,
}: {
  value: DailyFeeRevenueDateRange;
  onChange: (range: DailyFeeRevenueDateRange) => void;
  onApply: () => void;
  loading: boolean;
}) {
  const [open, setOpen] = useState(false);
  const validationError = validateDailyFeeRevenueDateRange(value);
  const presets = [
    { label: "7D", days: 7 },
    { label: "30D", days: 30 },
    { label: "90D", days: 90 },
    { label: "180D", days: 180 },
  ];

  function update(field: keyof DailyFeeRevenueDateRange, nextValue: string) {
    onChange({ ...value, [field]: nextValue });
  }

  function applyPreset(days: number) {
    const now = new Date();
    const endDate = new Date(
      Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate())
    );
    const startDate = new Date(endDate);
    startDate.setUTCDate(startDate.getUTCDate() - (days - 1));
    onChange({
      start_date: formatDateParam(startDate),
      end_date: formatDateParam(endDate),
    });
  }

  function applyAndClose() {
    if (validationError) return;
    onApply();
    setOpen(false);
  }

  return (
    <Popover open={open} onOpenChange={setOpen}>
      <PopoverTrigger asChild>
        <button
          type="button"
          className="flex min-h-11 w-full items-center justify-between gap-3 rounded-xl border border-(--line-subtle) bg-(--bg-surface-secondary) px-3 py-2 text-left transition-colors hover:border-(--line-strong) hover:bg-(--bg-hover) sm:w-auto sm:min-w-[320px]"
        >
          <span className="flex min-w-0 items-center gap-2">
            <span className="flex h-8 w-8 shrink-0 items-center justify-center rounded-lg bg-[rgba(188,135,255,0.12)] text-(--fg-brand)">
              <CalendarDays className="h-4 w-4" />
            </span>
            <span className="min-w-0">
              <span className="block text-[10px] font-semibold uppercase tracking-[0.16em] text-(--fg-tertiary)">
                Settlement period
              </span>
              <span className="block truncate text-sm font-medium text-(--fg-primary)">
                {formatDate(value.start_date)} - {formatDate(value.end_date)}
              </span>
            </span>
          </span>
          <ChevronDown
            className={`h-4 w-4 shrink-0 text-(--fg-secondary) transition-transform ${open ? "rotate-180" : ""}`}
          />
        </button>
      </PopoverTrigger>
      <PopoverContent
        align="end"
        className="w-[360px] rounded-2xl border border-(--line-subtle) bg-(--bg-popout) p-4 text-(--fg-primary) shadow-xl"
      >
        <div className="mb-4">
          <p className="text-sm font-semibold text-(--fg-primary)">
            Date range
          </p>
          <p className="mt-1 text-xs text-(--fg-secondary)">
            Enter dates as YYYY-MM-DD. Maximum range is 180 days.
          </p>
        </div>

        <div className="grid grid-cols-1 gap-3 sm:grid-cols-2">
          <label className="block text-xs font-medium text-(--fg-secondary)">
            Start date
            <input
              type="text"
              inputMode="numeric"
              pattern="\d{4}-\d{2}-\d{2}"
              placeholder="YYYY-MM-DD"
              value={value.start_date}
              onChange={event => update("start_date", event.target.value)}
              className={`mt-1 h-10 w-full rounded-lg border bg-(--bg-input) px-3 font-mono text-sm text-(--fg-primary) outline-none transition-colors placeholder:text-(--fg-placeholder) focus:border-(--line-brand) ${validationError ? "border-(--line-negative)" : "border-(--line-subtle)"}`}
            />
          </label>
          <label className="block text-xs font-medium text-(--fg-secondary)">
            End date
            <input
              type="text"
              inputMode="numeric"
              pattern="\d{4}-\d{2}-\d{2}"
              placeholder="YYYY-MM-DD"
              value={value.end_date}
              onChange={event => update("end_date", event.target.value)}
              className={`mt-1 h-10 w-full rounded-lg border bg-(--bg-input) px-3 font-mono text-sm text-(--fg-primary) outline-none transition-colors placeholder:text-(--fg-placeholder) focus:border-(--line-brand) ${validationError ? "border-(--line-negative)" : "border-(--line-subtle)"}`}
            />
          </label>
        </div>

        {validationError && (
          <p className="mt-3 text-xs text-(--fg-negative)">{validationError}</p>
        )}

        <div className="mt-4 grid grid-cols-4 gap-2">
          {presets.map(preset => (
            <button
              key={preset.label}
              type="button"
              onClick={() => applyPreset(preset.days)}
              className="rounded-lg border border-(--line-subtle) px-3 py-2 text-xs font-medium text-(--fg-secondary) transition-colors hover:bg-(--bg-hover) hover:text-(--fg-primary)"
            >
              {preset.label}
            </button>
          ))}
        </div>

        <div className="mt-4 flex justify-end gap-2">
          <button
            type="button"
            onClick={() => setOpen(false)}
            className="rounded-lg border border-(--line-subtle) px-3 py-2 text-sm font-medium text-(--fg-primary) transition-colors hover:bg-(--bg-hover)"
          >
            Cancel
          </button>
          <button
            type="button"
            onClick={applyAndClose}
            disabled={loading || Boolean(validationError)}
            className="rounded-lg px-4 py-2 text-sm font-semibold text-white transition-opacity hover:opacity-90 disabled:cursor-not-allowed disabled:opacity-50"
            style={{ background: "var(--bg-brand-grad)" }}
          >
            {loading ? "Loading..." : "Apply"}
          </button>
        </div>
      </PopoverContent>
    </Popover>
  );
}

